798:     ConsumerGroup getOrMaybeCreateConsumerGroup(
799:         String groupId,
800:         boolean createIfNotExists,
801:         List<CoordinatorRecord> records
802:     ) throws GroupIdNotFoundException {
803:         Group group = groups.get(groupId);
804: 
805:         if (group == null && !createIfNotExists) {
806:             throw new GroupIdNotFoundException(String.format("Consumer group %s not found.", groupId));
807:         }
808: 
809:         if (group == null) {
