1411:     /**
1412:      * Verifies that the partitions currently owned by the member (the ones set in the
1413:      * request) matches the ones that the member should own. It matches if the consumer
1414:      * only owns partitions which are in the assigned partitions. It does not match if
1415:      * it owns any other partitions.
1416:      *
1417:      * @param ownedTopicPartitions  The partitions provided by the consumer in the request.
1418:      * @param target                The partitions that the member should have.
1419:      *
1420:      * @return A boolean indicating whether the owned partitions are a subset or not.
1421:      */
1422:     private static boolean isSubset(
1423:         List<ConsumerGroupHeartbeatRequestData.TopicPartitions> ownedTopicPartitions,
1424:         Map<Uuid, Set<Integer>> target
1425:     ) {
1426:         if (ownedTopicPartitions == null) return false;
1427: 
1428:         for (ConsumerGroupHeartbeatRequestData.TopicPartitions topicPartitions : ownedTopicPartitions) {
1429:             Set<Integer> partitions = target.get(topicPartitions.topicId());
1430:             if (partitions == null) return false;
1431:             for (Integer partitionId : topicPartitions.partitions()) {
1432:                 if (!partitions.contains(partitionId)) return false;
1433:             }
1434:         }
1435: 
1436:         return true;
1437:     }
