1566:     ) {
1567:         // Epoch 0 is a special value indicating the member wants to (re)join the group.
1568:         // This is valid per KIP-848 fenced member recovery protocol.
1569:         if (receivedMemberEpoch == 0) return;
1570: 
1571:         if (receivedMemberEpoch > member.memberEpoch()) {
1572:             throw new FencedMemberEpochException("The consumer group member has a greater member "
1573:                 + "epoch (" + receivedMemberEpoch + ") than the one known by the group coordinator ("
1574:                 + member.memberEpoch() + "). The member must abandon all its partitions and rejoin.");
1575:         } else if (receivedMemberEpoch < member.memberEpoch()) {
1576:             // If the member comes with the previous epoch and has a subset of the current assignment partitions,
1577:             // we accept it because the response with the bumped epoch may have been lost.
1578:             if (receivedMemberEpoch != member.previousMemberEpoch() || !isSubset(ownedTopicPartitions, member.assignedPartitions())) {
1579:                 throw new FencedMemberEpochException("The consumer group member has a smaller member "
1580:                     + "epoch (" + receivedMemberEpoch + ") than the one known by the group coordinator ("
1581:                     + member.memberEpoch() + "). The member must abandon all its partitions and rejoin.");
