1205:     private boolean validateOnlineDowngradeWithFencedMembers(ConsumerGroup consumerGroup, Set<ConsumerGroupMember> fencedMembers) {
1206:         if (!consumerGroup.allMembersUseClassicProtocolExcept(fencedMembers)) {
1207:             return false;
1208:         } else if (consumerGroup.numMembers() - fencedMembers.size() <= 0) {
1209:             log.debug("Skip downgrading the consumer group {} to classic group because it's empty.",
1210:                 consumerGroup.groupId());
1211:             return false;
1212:         } else if (!config.consumerGroupMigrationPolicy().isDowngradeEnabled()) {
1213:             log.info("Cannot downgrade consumer group {} to classic group because the online downgrade is disabled.",
1214:                 consumerGroup.groupId());
1215:             return false;
1216:         } else if (consumerGroup.numMembers() - fencedMembers.size() > config.classicGroupMaxSize()) {
1217:             log.info("Cannot downgrade consumer group {} to classic group because its group size is greater than classic group max size.",
1218:                 consumerGroup.groupId());
1219:             return false;
1220:         }
1221:         return true;
1222:     }
