1346:     /**
1347:      * Creates a ConsumerGroup corresponding to the given classic group.
1348:      *
1349:      * @param classicGroup  The ClassicGroup to convert.
1350:      * @param records       The list of Records.
1351:      * @return The created ConsumerGroup.
1352:      */
1353:     ConsumerGroup convertToConsumerGroup(ClassicGroup classicGroup, List<CoordinatorRecord> records) {
1354:         // The upgrade is always triggered by a new member joining the classic group, which always results in
1355:         // updatedMember.subscribedTopicNames changing, the group epoch being bumped, and triggering a new rebalance.
1356:         // If the ClassicGroup is rebalancing, inform the awaiting consumers of another ongoing rebalance
1357:         // so that they will rejoin for the new rebalance.
1358:         classicGroup.completeAllJoinFutures(Errors.REBALANCE_IN_PROGRESS);
1359:         classicGroup.completeAllSyncFutures(Errors.REBALANCE_IN_PROGRESS);
1360: 
1361:         classicGroup.createGroupTombstoneRecords(records);
1362: 
1363:         ConsumerGroup consumerGroup;
1364:         try {
1365:             consumerGroup = ConsumerGroup.fromClassicGroup(
1366:                 logContext,
1367:                 snapshotRegistry,
1368:                 classicGroup,
1369:                 topicHashCache,
1370:                 metadataImage
1371:             );
1372:         } catch (SchemaException e) {
1373:             log.warn("Cannot upgrade classic group {} to consumer group because the embedded consumer protocol is malformed: {}.",
1374:                 classicGroup.groupId(), e.getMessage(), e);
1375: 
1376:             throw new GroupIdNotFoundException(
1377:                 String.format("Cannot upgrade classic group %s to consumer group because the embedded consumer protocol is malformed.", classicGroup.groupId())
1378:             );
1379:         } catch (UnsupportedVersionException e) {
1380:             log.warn("Cannot upgrade classic group {} to consumer group: {}.", classicGroup.groupId(), e.getMessage(), e);
1381: 
1382:             throw new GroupIdNotFoundException(
1383:                 String.format("Cannot upgrade classic group %s to consumer group because an unsupported custom assignor is in use. " +
1384:                     "Please refer to the documentation or switch to a default assignor before re-attempting the upgrade.", classicGroup.groupId())
1385:             );
1386:         }
1387:         consumerGroup.createConsumerGroupRecords(records);
1388: 
1389:         // Create the session timeouts for the new members. If the conversion fails, the group will remain a
1390:         // classic group, thus these timers will fail the group type check and do nothing.
1391:         consumerGroup.members().forEach((memberId, member) ->
1392:             scheduleConsumerGroupSessionTimeout(consumerGroup.groupId(), memberId, member.classicProtocolSessionTimeout().get())
1393:         );
1394: 
1395:         log.info("[GroupId {}] Converted the classic group to a consumer group.", classicGroup.groupId());
1396: 
1397:         return consumerGroup;
1398:     }
